import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

// Explicit type annotations
const params: Anthropic.MessageCreateParams = {
  max_tokens: 1024,
  messages: [{ role: "user", content: "Hello, Claude" }],
  model: "claude-opus-4-8",
};

const message: Anthropic.Message = await client.messages.create(params);

console.log(message.content);

// ✅ CORRECT - system as top-level parameter
const response = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  system: "You are a Python coding assistant.",  // Top-level
  messages: [
    { role: "user", content: "How do I reverse a list?" }
  ],
});

// ❌ WRONG - system as message role (raises error)
const response = await client.messages.create({
  messages: [
    { role: "system", content: "..." }  // ERROR! "system" not valid role
  ],
});

import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

// Start conversation
const messages = [
  { role: "user", content: "What is the Zen of Python?" }
];

const response = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  messages: messages,
});

console.log(response.content[0].text);

// Add assistant response to history
messages.push({ role: "assistant", content: response.content });

// Next turn
messages.push({ role: "user", content: "Can you show me an example?" });

const response2 = await client.messages.create({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  messages: messages,  // Full history
});

console.log(response2.content[0].text);

import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

const messages: Anthropic.MessageParam[] = [];

console.log("Chat with Claude (type 'quit' to exit)");

while (true) {
  const userInput = await prompt("You: ");

  if (userInput.toLowerCase() === "quit") {
    break;
  }

  messages.push({ role: "user", content: userInput });

  const response = await client.messages.create({
    model: "claude-sonnet-4-6",
    max_tokens: 1024,
    messages: messages,
  });

  const assistantResponse = response.content[0].text;
  console.log(`Claude: ${assistantResponse}`);

  messages.push({ role: "assistant", content: response.content });
}

