import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();

const stream = client.messages.stream({
  messages: [
    {
      role: "user",
      content: `Hey Claude!
How can I recursively list all files in a directory in Rust?`,
    },
  ],
  model: "claude-sonnet-4-20250514",
  max_tokens: 1024,
})
  .on("contentBlock", (content) => console.log("contentBlock", content))
  .on("message", (message) => console.log("message", message));

for await (const event of stream) {
  console.log("event", event);
}

const message = await stream.finalMessage();
console.log("finalMessage", message);

const stream = await client.messages.create({
  max_tokens: 1024,
  messages: [{ role: "user", content: "Hello, Claude" }],
  model: "claude-opus-4-8",
  stream: true,
});

// Break from the loop to cancel
for await (const event of stream) {
  console.log(event.type);
  if (event.type === "message_delta") {
    break;  // Cancel stream
  }
}

// Or call abort()
stream.controller.abort();

// Only returns async iterable of events (no final message object)
const stream = await client.messages.create({
  max_tokens: 1024,
  messages: [{ role: "user", content: "Hello, Claude" }],
  model: "claude-opus-4-8",
